void ZopfliCleanCache(ZopfliLongestMatchCache *lmc)
__CPROVER_requires(__CPROVER_is_fresh(lmc, sizeof(*lmc)))
__CPROVER_requires(__CPROVER_is_fresh(lmc->length, sizeof(unsigned short)))
__CPROVER_requires(__CPROVER_is_fresh(lmc->dist, sizeof(unsigned short)))
__CPROVER_requires(__CPROVER_is_fresh(lmc->sublen, sizeof(unsigned char)))
__CPROVER_assigns()
{
    free(lmc->length);
    free(lmc->dist);
    free(lmc->sublen);
}

void ZopfliCleanBlockState(ZopfliBlockState *s)
{
    if (s->lmc)
    {
        ZopfliCleanCache(s->lmc);
        free(s->lmc);
    }
}

void ZopfliInitCache(size_t blocksize, ZopfliLongestMatchCache *lmc)
{
    size_t i;
    lmc->length = (unsigned short *)malloc(sizeof(unsigned short) * blocksize);
    lmc->dist = (unsigned short *)malloc(sizeof(unsigned short) * blocksize);
    /* Rather large amount of memory. */
    lmc->sublen = (unsigned char *)malloc(ZOPFLI_CACHE_LENGTH * 3 * blocksize);
    if (lmc->sublen == NULL)
    {
        fprintf(stderr,
                "Error: Out of memory. Tried allocating %lu bytes of memory.\n",
                (unsigned long)ZOPFLI_CACHE_LENGTH * 3 * blocksize);
        exit(EXIT_FAILURE);
    }

    /* length > 0 and dist 0 is invalid combination, which indicates on purpose
    that this cache value is not filled in yet. */
    for (i = 0; i < blocksize; i++)
        lmc->length[i] = 1;
    for (i = 0; i < blocksize; i++)
        lmc->dist[i] = 0;
    for (i = 0; i < ZOPFLI_CACHE_LENGTH * blocksize * 3; i++)
        lmc->sublen[i] = 0;
}

void ZopfliInitBlockState(const ZopfliOptions *options,
                          size_t blockstart, size_t blockend, int add_lmc,
                          ZopfliBlockState *s)
{
    s->options = options;
    s->blockstart = blockstart;
    s->blockend = blockend;
    if (add_lmc)
    {
        s->lmc = (ZopfliLongestMatchCache *)malloc(sizeof(ZopfliLongestMatchCache));
        ZopfliInitCache(blockend - blockstart, s->lmc);
    }
    else
    {
        s->lmc = 0;
    }

typedef struct ZopfliLongestMatchCache
{
    unsigned short *length;
    unsigned short *dist;
    unsigned char *sublen;
} ZopfliLongestMatchCache;

/* for size_t */
/*
Options used throughout the program.
*/
typedef struct ZopfliOptions
{
    /* Whether to print output */
    int verbose;

    /* Whether to print more detailed output */
    int verbose_more;

    /*
    Maximum amount of times to rerun forward and backward pass to optimize LZ77
    compression cost. Good values: 10, 15 for small files, 5 for files over
    several MB in size or it will be too slow.
    */
    int numiterations;

    /*
    If true, splits the data in multiple deflate blocks with optimal choice
    for the block boundaries. Block splitting gives better compression. Default:
    true (1).
    */
    int blocksplitting;

    /*
    No longer used, left for compatibility.
    */
    int blocksplittinglast;

    /*
    Maximum amount of blocks to split into (0 for unlimited, but this can give
    extreme results that hurt compression on some files). Default value: 15.
    */
    int blocksplittingmax;
} ZopfliOptions;

/*
Some state information for compressing a block.
This is currently a bit under-used (with mainly only the longest match cache),
but is kept for easy future expansion.
*/
typedef struct ZopfliBlockState
{
    const ZopfliOptions *options;

    /* Cache for length/distance pairs found so far. */
    ZopfliLongestMatchCache *lmc;

    /* The start (inclusive) and end (not inclusive) of the current block. */
    size_t blockstart;
    size_t blockend;
} ZopfliBlockState;

